<template><view class="page"><view class="title">亲友圈</view><AppCard v-for="x in items" :key="x.id" :title="x.nickname||x.relationType"><view>{{x.status}}</view><button class="btn secondary" @click="go(x.id)">发送留言</button></AppCard><button class="btn" @click="invite">邀请好友</button></view></template><script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import{qingxierApi}from'@/services/api';const items=ref<any[]>([]);onShow(async()=>items.value=await qingxierApi.relations());async function invite(){await qingxierApi.invite({targetUserId:'u_2',relationType:'bestie',nickname:'好友'});uni.showToast({title:'邀请已发送'})}function go(id:string){uni.navigateTo({url:`/pages/messages/index?relationId=${id}`})}</script>
